/**
 * SQLite 数据库初始化与连接
 */
const Database = require('better-sqlite3');
const path = require('path');
const fs = require('fs');

const DB_PATH = path.join(__dirname, '..', 'data', 'autoconfig.db');

let db;

function getDb() {
    if (!db) {
        const dataDir = path.dirname(DB_PATH);
        if (!fs.existsSync(dataDir)) {
            fs.mkdirSync(dataDir, { recursive: true });
        }
        db = new Database(DB_PATH);
        db.pragma('journal_mode = WAL');
        db.pragma('foreign_keys = ON');
    }
    return db;
}

function initDatabase() {
    const db = getDb();

    db.exec(`
        CREATE TABLE IF NOT EXISTS users (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            username TEXT UNIQUE NOT NULL,
            email TEXT UNIQUE NOT NULL,
            password TEXT NOT NULL,
            avatar TEXT DEFAULT '',
            bio TEXT DEFAULT '',
            coins INTEGER DEFAULT 0,
            role TEXT DEFAULT 'user',
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
        );

        CREATE TABLE IF NOT EXISTS projects (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            user_id INTEGER NOT NULL,
            name TEXT NOT NULL,
            slug TEXT NOT NULL,
            description TEXT DEFAULT '',
            is_public INTEGER DEFAULT 0,
            status TEXT DEFAULT 'active',
            file_count INTEGER DEFAULT 0,
            total_size INTEGER DEFAULT 0,
            visit_count INTEGER DEFAULT 0,
            deployed_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
            UNIQUE(user_id, slug)
        );

        CREATE INDEX IF NOT EXISTS idx_projects_user ON projects(user_id);
        CREATE INDEX IF NOT EXISTS idx_projects_public ON projects(is_public);
        CREATE INDEX IF NOT EXISTS idx_projects_slug ON projects(user_id, slug);

        CREATE TABLE IF NOT EXISTS likes (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            user_id INTEGER NOT NULL,
            project_id INTEGER NOT NULL,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
            FOREIGN KEY (project_id) REFERENCES projects(id) ON DELETE CASCADE,
            UNIQUE(user_id, project_id)
        );

        CREATE TABLE IF NOT EXISTS comments (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            user_id INTEGER NOT NULL,
            project_id INTEGER NOT NULL,
            content TEXT NOT NULL,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
            FOREIGN KEY (project_id) REFERENCES projects(id) ON DELETE CASCADE
        );

        CREATE INDEX IF NOT EXISTS idx_likes_project ON likes(project_id);
        CREATE INDEX IF NOT EXISTS idx_comments_project ON comments(project_id);

        CREATE TABLE IF NOT EXISTS templates (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            name TEXT NOT NULL,
            slug TEXT UNIQUE NOT NULL,
            description TEXT DEFAULT '',
            category TEXT NOT NULL DEFAULT 'website',
            difficulty TEXT NOT NULL DEFAULT 'easy',
            price INTEGER NOT NULL DEFAULT 0,
            preview_html TEXT NOT NULL DEFAULT '',
            html_content TEXT NOT NULL DEFAULT '',
            css_content TEXT DEFAULT '',
            js_content TEXT DEFAULT '',
            tags TEXT DEFAULT '',
            download_count INTEGER DEFAULT 0,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP
        );

        CREATE TABLE IF NOT EXISTS purchases (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            user_id INTEGER NOT NULL,
            template_id INTEGER NOT NULL,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
            FOREIGN KEY (template_id) REFERENCES templates(id) ON DELETE CASCADE,
            UNIQUE(user_id, template_id)
        );

        CREATE TABLE IF NOT EXISTS coin_transactions (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            user_id INTEGER NOT NULL,
            amount INTEGER NOT NULL,
            type TEXT NOT NULL,
            description TEXT DEFAULT '',
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
        );

        CREATE INDEX IF NOT EXISTS idx_purchases_user ON purchases(user_id);
        CREATE INDEX IF NOT EXISTS idx_coin_tx_user ON coin_transactions(user_id);

        CREATE TABLE IF NOT EXISTS messages (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            from_id INTEGER NOT NULL,
            to_id INTEGER NOT NULL,
            content TEXT NOT NULL,
            type TEXT DEFAULT 'text',
            is_read INTEGER DEFAULT 0,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            FOREIGN KEY (from_id) REFERENCES users(id) ON DELETE CASCADE,
            FOREIGN KEY (to_id) REFERENCES users(id) ON DELETE CASCADE
        );

        CREATE INDEX IF NOT EXISTS idx_messages_from ON messages(from_id);
        CREATE INDEX IF NOT EXISTS idx_messages_to ON messages(to_id);
        CREATE INDEX IF NOT EXISTS idx_messages_pair ON messages(from_id, to_id);
    `);

    // 兼容旧版数据库：为 users 表添加 coins 列
    try { db.exec('ALTER TABLE users ADD COLUMN coins INTEGER DEFAULT 0'); } catch(e) {}
    // 兼容旧版数据库：为 users 表添加 role 列
    try { db.exec("ALTER TABLE users ADD COLUMN role TEXT DEFAULT 'user'"); } catch(e) {}

    // 创建/更新 admin 用户
    seedAdmin(db);

    // 初始化模板数据
    seedTemplates(db);

    console.log('  ✅ 数据库初始化完成');
}

module.exports = { getDb, initDatabase };

// ===== 管理员种子账号 =====
function seedAdmin(db) {
    const bcrypt = require('bcryptjs');
    const existing = db.prepare('SELECT id, role FROM users WHERE username = ?').get('admin');
    if (existing) {
        // 确保 admin 始终拥有正确的角色和无限金币
        db.prepare('UPDATE users SET role = ?, coins = ? WHERE id = ?').run('admin', 999999, existing.id);
        return;
    }
    // 创建 admin 账号
    const hashedPassword = bcrypt.hashSync('admin1234', 10);
    db.prepare(
        'INSERT INTO users (username, email, password, coins, role, bio) VALUES (?, ?, ?, ?, ?, ?)'
    ).run('admin', 'admin@autoconfig.dev', hashedPassword, 999999, 'admin', '系统管理员');
    console.log('  👑 管理员账号已创建 (admin / admin1234)');
}

