            description: '赛博朋克风格个人作品集网站，霓虹灯光效果，科幻感满满',
            tags: '作品集,赛博朋克,高级',
            preview_html: '<div style="background:#0a0a0a;padding:24px;font-family:sans-serif;min-height:300px;position:relative;overflow:hidden"><div style="position:absolute;top:0;left:0;right:0;height:2px;background:linear-gradient(90deg,transparent,#0ff,transparent);animation:scan 2s infinite"></div><div style="max-width:480px;margin:0 auto;text-align:center"><h1 style="font-size:2.2rem;color:#0ff;text-shadow:0 0 20px #0ff,0 0 40px #0ff;font-family:monospace;margin-bottom:8px">CYBER_DEV</h1><p style="color:#f0f;font-family:monospace;text-shadow:0 0 10px #f0f;margin-bottom:24px">// full-stack developer</p><div style="display:grid;grid-template-columns:1fr 1fr;gap:12px"><div style="background:rgba(0,255,255,.05);border:1px solid rgba(0,255,255,.2);border-radius:8px;padding:16px"><div style="color:#0ff;font-family:monospace;font-size:.8rem">PROJECT_01</div><div style="color:#888;font-size:.75rem;margin-top:4px">Web3 DApp</div></div><div style="background:rgba(255,0,255,.05);border:1px solid rgba(255,0,255,.2);border-radius:8px;padding:16px"><div style="color:#f0f;font-family:monospace;font-size:.8rem">PROJECT_02</div><div style="color:#888;font-size:.75rem;margin-top:4px">AI Tool</div></div></div></div></div>',
            html_content: '<!DOCTYPE html>\n<html lang="zh-CN">\n<head>\n<meta charset="UTF-8">\n<meta name="viewport" content="width=device-width, initial-scale=1.0">\n<title>CYBER_DEV Portfolio</title>\n<link rel="stylesheet" href="style.css">\n</head>\n<body>\n<div class="scan-line"></div>\n<div class="glitch-bg"></div>\n<header class="hero">\n<h1 class="glitch" data-text="CYBER_DEV">CYBER_DEV</h1>\n<p class="tagline">// full-stack developer & creative coder</p>\n<div class="cta"><a href="#work" class="btn-neon cyan">查看作品</a><a href="#" class="btn-neon pink">联系我</a></div>\n</header>\n<section id="work" class="section">\n<h2 class="section-title">&gt; PROJECTS_</h2>\n<div class="grid">\n<div class="card cyan"><div class="card-title">PROJECT_01</div><div class="card-desc">去中心化投票 DApp</div><div class="card-tags"><span>Solidity</span><span>React</span></div></div>\n<div class="card pink"><div class="card-title">PROJECT_02</div><div class="card-desc">AI 图像生成工具</div><div class="card-tags"><span>Python</span><span>PyTorch</span></div></div>\n<div class="card yellow"><div class="card-title">PROJECT_03</div><div class="card-desc">实时协作编辑器</div><div class="card-tags"><span>Node.js</span><span>WebSocket</span></div></div>\n<div class="card cyan"><div class="card-title">PROJECT_04</div><div class="card-desc">3D 数据可视化</div><div class="card-tags"><span>Three.js</span><span>D3</span></div></div>\n</div>\n</section>\n<footer class="footer">&gt; SYSTEM.exit() <span class="blink">_</span></footer>\n<script src="script.js"></script>\n</body>\n</html>',
            css_content: '*{margin:0;padding:0;box-sizing:border-box}:root{--cyan:#0ff;--pink:#f0f;--yellow:#ff0}\nbody{background:#0a0a0a;color:#eee;font-family:"Courier New",monospace;overflow-x:hidden}\n.scan-line{position:fixed;top:0;left:0;right:0;height:2px;background:linear-gradient(90deg,transparent,var(--cyan),transparent);z-index:999;animation:scan 3s linear infinite}\n@keyframes scan{0%{top:0}100%{top:100vh}}\n.hero{text-align:center;padding:120px 20px 80px;position:relative}\n.glitch{font-size:4rem;color:var(--cyan);text-shadow:0 0 20px var(--cyan),0 0 60px var(--cyan);margin-bottom:12px}\n.tagline{color:var(--pink);text-shadow:0 0 10px var(--pink);font-size:1.1rem;margin-bottom:40px}\n.cta{display:flex;gap:16px;justify-content:center}\n.btn-neon{padding:12px 32px;border:2px solid;border-radius:4px;text-decoration:none;font-family:inherit;font-weight:700;text-transform:uppercase;letter-spacing:2px;font-size:.8rem;transition:all .3s}\n.btn-neon.cyan{color:var(--cyan);border-color:var(--cyan);box-shadow:0 0 10px rgba(0,255,255,.2)}\n.btn-neon.cyan:hover{background:rgba(0,255,255,.1);box-shadow:0 0 30px rgba(0,255,255,.4)}\n.btn-neon.pink{color:var(--pink);border-color:var(--pink);box-shadow:0 0 10px rgba(255,0,255,.2)}\n.btn-neon.pink:hover{background:rgba(255,0,255,.1);box-shadow:0 0 30px rgba(255,0,255,.4)}\n.section{max-width:900px;margin:0 auto;padding:60px 20px}\n.section-title{font-size:1.5rem;color:var(--cyan);margin-bottom:32px}\n.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:20px}\n.card{border:1px solid rgba(255,255,255,.1);border-radius:8px;padding:24px;transition:all .3s;position:relative;overflow:hidden}\n.card::before{content:"";position:absolute;top:0;left:0;right:0;height:2px}\n.card.cyan{border-color:rgba(0,255,255,.15)}.card.cyan::before{background:var(--cyan)}.card.cyan:hover{box-shadow:0 0 30px rgba(0,255,255,.15)}\n.card.pink{border-color:rgba(255,0,255,.15)}.card.pink::before{background:var(--pink)}.card.pink:hover{box-shadow:0 0 30px rgba(255,0,255,.15)}\n.card.yellow{border-color:rgba(255,255,0,.15)}.card.yellow::before{background:var(--yellow)}.card.yellow:hover{box-shadow:0 0 30px rgba(255,255,0,.15)}\n.card-title{font-size:1rem;margin-bottom:8px;color:#fff}\n.card-desc{font-size:.85rem;color:#888;margin-bottom:16px}\n.card-tags{display:flex;gap:8px}\n.card-tags span{font-size:.7rem;padding:4px 10px;border:1px solid rgba(255,255,255,.15);border-radius:12px;color:#aaa}\n.footer{text-align:center;padding:40px;color:#555;font-size:.9rem}\n.blink{animation:blink 1s infinite}@keyframes blink{0%,50%{opacity:1}51%,100%{opacity:0}}',
            js_content: '// Glitch effect on hover\nconst glitch=document.querySelector(".glitch");if(glitch){let interval;glitch.addEventListener("mouseenter",()=>{interval=setInterval(()=>{glitch.style.textShadow=`${Math.random()*6-3}px ${Math.random()*6-3}px var(--cyan), ${Math.random()*6-3}px ${Math.random()*6-3}px var(--pink)`;},50)});glitch.addEventListener("mouseleave",()=>{clearInterval(interval);glitch.style.textShadow="0 0 20px var(--cyan), 0 0 60px var(--cyan)"})}'
